import { useState } from 'react';

// SMA Analysis Tab Component
const SMAAnalysisTab = ({ smaData, loading, indices, onFetchSMA, currentPeriod, currentTimeframe }) => {
  const [selectedTimeframe, setSelectedTimeframe] = useState(`${currentPeriod || 20}-${currentTimeframe || 'monthly'}`);
  const [localLoading, setLocalLoading] = useState(false);

  // Fetch SMA data when timeframe changes
  const handleTimeframeChange = async (e) => {
    const newValue = e.target.value;
    setSelectedTimeframe(newValue);
    setLocalLoading(true);
    const [period, timeframe] = newValue.split('-');
    await onFetchSMA(parseInt(period), timeframe);
    setLocalLoading(false);
  };

  // Get timeframe label
  const getTimeframeLabel = () => {
    const [period, timeframe] = selectedTimeframe.split('-');
    const unit = timeframe === 'monthly' ? 'Month' : 'Day';
    return `${period}-${unit} SMA`;
  };

  const isLoading = loading || localLoading;

  return (
    <div className="tab-content">
      <h2 className="section-title">📈 SMA Analysis - Bollinger Bands Style</h2>
      <p className="section-subtitle" style={{color: 'var(--text-secondary)', fontSize: '0.875rem', marginBottom: '1rem'}}>
        Uses monthly closing prices for SMA calculation (e.g., 20-Month SMA = middle line of Bollinger Bands on monthly chart)
      </p>
      
      <div className="sma-controls">
        <label style={{marginRight: '0.5rem', color: 'var(--text-secondary)'}}>Timeframe:</label>
        <select 
          value={selectedTimeframe}
          onChange={handleTimeframeChange}
          className="index-select"
          data-testid="sma-timeframe-select"
          disabled={isLoading}
        >
          <option value="9-daily">9-Day SMA</option>
          <option value="20-daily">20-Day SMA</option>
          <option value="50-daily">50-Day SMA</option>
          <option value="9-monthly">9-Month SMA</option>
          <option value="20-monthly">20-Month SMA (Bollinger)</option>
          <option value="50-monthly">50-Month SMA</option>
        </select>
        {isLoading && <span style={{marginLeft: '0.5rem', color: 'var(--text-muted)'}}>Loading...</span>}
      </div>

      {isLoading ? (
        <div className="loading-sma">
          <div className="skeleton-chart"></div>
        </div>
      ) : (
        <>
          <div className="sma-table">
            <table>
              <thead>
                <tr>
                  <th>Index</th>
                  <th>Current Price</th>
                  <th>{getTimeframeLabel()}</th>
                  <th>Upper Band</th>
                  <th>Lower Band</th>
                  <th>% Diff</th>
                  <th>Position</th>
                  <th>Signal</th>
                </tr>
              </thead>
              <tbody>
                {smaData.map((item, i) => (
                  <tr key={i} data-testid={`sma-row-${item.symbol}`}>
                    <td className="index-name">{item.name}</td>
                    <td>{item.lastPrice?.toLocaleString()}</td>
                    <td>{item.sma?.toLocaleString() || item.sma20?.toLocaleString()}</td>
                    <td style={{color: 'var(--accent-green)'}}>{item.upperBand?.toLocaleString() || '-'}</td>
                    <td style={{color: 'var(--accent-red)'}}>{item.lowerBand?.toLocaleString() || '-'}</td>
                    <td className={item.percentDiff >= 0 ? 'positive' : 'negative'}>
                      {item.percentDiff >= 0 ? '+' : ''}{item.percentDiff?.toFixed(2)}%
                    </td>
                    <td>
                      <span className={`position-badge ${item.position?.toLowerCase().replace(' ', '-')}`}>
                        {item.position}
                      </span>
                    </td>
                    <td>
                      <span className={`signal-badge ${item.bandPosition?.toLowerCase()}`}>
                        {item.bandPosition || 'Normal'}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          
          {/* Summary Section */}
          <div className="sma-summary" style={{marginTop: '1.5rem', display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: '1rem'}}>
            <div className="summary-box" style={{padding: '1rem', background: 'var(--bg-primary)', borderRadius: '0.5rem', border: '1px solid rgba(34, 197, 94, 0.3)'}}>
              <div style={{fontSize: '0.875rem', color: 'var(--text-secondary)', marginBottom: '0.5rem'}}>Above SMA</div>
              <div style={{fontSize: '1.5rem', fontWeight: 600, color: '#22c55e'}}>
                {smaData.filter(s => s.position === 'Above SMA').length}
              </div>
              <div style={{fontSize: '0.75rem', color: 'var(--text-muted)'}}>Bullish sectors</div>
            </div>
            <div className="summary-box" style={{padding: '1rem', background: 'var(--bg-primary)', borderRadius: '0.5rem', border: '1px solid rgba(234, 179, 8, 0.3)'}}>
              <div style={{fontSize: '0.875rem', color: 'var(--text-secondary)', marginBottom: '0.5rem'}}>At SMA</div>
              <div style={{fontSize: '1.5rem', fontWeight: 600, color: '#eab308'}}>
                {smaData.filter(s => s.position === 'At SMA').length}
              </div>
              <div style={{fontSize: '0.75rem', color: 'var(--text-muted)'}}>Neutral sectors</div>
            </div>
            <div className="summary-box" style={{padding: '1rem', background: 'var(--bg-primary)', borderRadius: '0.5rem', border: '1px solid rgba(239, 68, 68, 0.3)'}}>
              <div style={{fontSize: '0.875rem', color: 'var(--text-secondary)', marginBottom: '0.5rem'}}>Below SMA</div>
              <div style={{fontSize: '1.5rem', fontWeight: 600, color: '#ef4444'}}>
                {smaData.filter(s => s.position === 'Below SMA').length}
              </div>
              <div style={{fontSize: '0.75rem', color: 'var(--text-muted)'}}>Bearish sectors</div>
            </div>
            <div className="summary-box" style={{padding: '1rem', background: 'var(--bg-primary)', borderRadius: '0.5rem', border: '1px solid rgba(239, 68, 68, 0.5)'}}>
              <div style={{fontSize: '0.875rem', color: 'var(--text-secondary)', marginBottom: '0.5rem'}}>Overbought</div>
              <div style={{fontSize: '1.5rem', fontWeight: 600, color: '#dc2626'}}>
                {smaData.filter(s => s.bandPosition === 'Overbought').length}
              </div>
              <div style={{fontSize: '0.75rem', color: 'var(--text-muted)'}}>Above upper band</div>
            </div>
            <div className="summary-box" style={{padding: '1rem', background: 'var(--bg-primary)', borderRadius: '0.5rem', border: '1px solid rgba(34, 197, 94, 0.5)'}}>
              <div style={{fontSize: '0.875rem', color: 'var(--text-secondary)', marginBottom: '0.5rem'}}>Oversold</div>
              <div style={{fontSize: '1.5rem', fontWeight: 600, color: '#16a34a'}}>
                {smaData.filter(s => s.bandPosition === 'Oversold').length}
              </div>
              <div style={{fontSize: '0.75rem', color: 'var(--text-muted)'}}>Below lower band</div>
            </div>
          </div>
        </>
      )}
    </div>
  );
};

export default SMAAnalysisTab;
