import { useState, useEffect, useRef, useMemo } from 'react';

// Options Technical Analysis Tab (NIFTY 50 - 9 SMA, Weekly Pivots)
// SCALPING ONLY - Both CE and PE require 5-min confirmation
const OptionsAnalysisTab = ({ loading, technicalData, pivotData, onRefresh }) => {
  const [timeframe, setTimeframe] = useState('1H');
  
  // Timer state for CE confirmation
  const [ceElapsedSeconds, setCeElapsedSeconds] = useState(0);
  const ceEntryZoneStartRef = useRef(null);
  const ceTimerRef = useRef(null);
  const prevCeInZoneRef = useRef(false);
  
  // Timer state for PE confirmation
  const [peElapsedSeconds, setPeElapsedSeconds] = useState(0);
  const peEntryZoneStartRef = useRef(null);
  const peTimerRef = useRef(null);
  const prevPeInZoneRef = useRef(false);
  
  // Track when confirmation exits for cancellation detection
  const [cancelledSignal, setCancelledSignal] = useState(null);
  
  // Constants
  const CE_ENTRY_TOLERANCE = 10;
  const PE_MIN_DISTANCE = 20;
  const TREND_BUFFER = 15;
  const CONFIRMATION_TIME = 300;

  const getTrendIcon = (trend) => {
    if (trend === 'Bullish') return '📈';
    if (trend === 'Bearish') return '📉';
    return '➡️';
  };
  
  const trendData = useMemo(() => {
    const price = technicalData?.currentPrice || 0;
    const sma9 = technicalData?.sma9 || price;
    const distanceFromSMA = price - sma9;
    
    let trend = 'NEUTRAL';
    if (distanceFromSMA > TREND_BUFFER) {
      trend = 'BULLISH';
    } else if (distanceFromSMA < -TREND_BUFFER) {
      trend = 'BEARISH';
    }
    
    return {
      trend,
      distanceFromSMA,
      absDistance: Math.abs(distanceFromSMA),
      isAboveSMA: distanceFromSMA > 0,
      price,
      sma9
    };
  }, [technicalData?.currentPrice, technicalData?.sma9]);
  
  const ceInEntryZone = useMemo(() => {
    if (trendData.trend !== 'BULLISH') return false;
    return trendData.absDistance <= CE_ENTRY_TOLERANCE;
  }, [trendData]);
  
  const peInEntryZone = useMemo(() => {
    if (trendData.trend !== 'BEARISH') return false;
    return trendData.absDistance >= PE_MIN_DISTANCE;
  }, [trendData]);
  
  const ceIsConfirmed = ceInEntryZone && ceElapsedSeconds >= CONFIRMATION_TIME;
  const ceTimeInZone = ceInEntryZone ? ceElapsedSeconds : 0;
  
  const peIsConfirmed = peInEntryZone && peElapsedSeconds >= CONFIRMATION_TIME;
  const peTimeInZone = peInEntryZone ? peElapsedSeconds : 0;
  
  // CE Timer Effect
  useEffect(() => {
    if (ceTimerRef.current) {
      clearInterval(ceTimerRef.current);
      ceTimerRef.current = null;
    }
    
    if (ceInEntryZone && !prevCeInZoneRef.current) {
      ceEntryZoneStartRef.current = Date.now();
    } else if (!ceInEntryZone && prevCeInZoneRef.current) {
      ceEntryZoneStartRef.current = null;
    }
    prevCeInZoneRef.current = ceInEntryZone;
    
    if (ceInEntryZone) {
      ceTimerRef.current = setInterval(() => {
        if (ceEntryZoneStartRef.current) {
          const elapsed = Math.floor((Date.now() - ceEntryZoneStartRef.current) / 1000);
          setCeElapsedSeconds(elapsed);
        }
      }, 1000);
      
      if (ceEntryZoneStartRef.current) {
        setCeElapsedSeconds(Math.floor((Date.now() - ceEntryZoneStartRef.current) / 1000));
      }
    } else {
      setCeElapsedSeconds(0);
    }
    
    return () => {
      if (ceTimerRef.current) clearInterval(ceTimerRef.current);
    };
  }, [ceInEntryZone]);
  
  // PE Timer Effect
  useEffect(() => {
    if (peTimerRef.current) {
      clearInterval(peTimerRef.current);
      peTimerRef.current = null;
    }
    
    if (peInEntryZone && !prevPeInZoneRef.current) {
      peEntryZoneStartRef.current = Date.now();
    } else if (!peInEntryZone && prevPeInZoneRef.current) {
      peEntryZoneStartRef.current = null;
    }
    prevPeInZoneRef.current = peInEntryZone;
    
    if (peInEntryZone) {
      peTimerRef.current = setInterval(() => {
        if (peEntryZoneStartRef.current) {
          const elapsed = Math.floor((Date.now() - peEntryZoneStartRef.current) / 1000);
          setPeElapsedSeconds(elapsed);
        }
      }, 1000);
      
      if (peEntryZoneStartRef.current) {
        setPeElapsedSeconds(Math.floor((Date.now() - peEntryZoneStartRef.current) / 1000));
      }
    } else {
      setPeElapsedSeconds(0);
    }
    
    return () => {
      if (peTimerRef.current) clearInterval(peTimerRef.current);
    };
  }, [peInEntryZone]);
  
  // Track cancellations using refs (updated in effects, read in render)
  const prevCeElapsedRef = useRef(0);
  const ceCancelledRef = useRef(false);
  useEffect(() => {
    if (!ceInEntryZone && prevCeElapsedRef.current > 0 && prevCeElapsedRef.current < CONFIRMATION_TIME && !ceCancelledRef.current) {
      ceCancelledRef.current = true;
    }
    if (ceInEntryZone) {
      ceCancelledRef.current = false;
    }
    prevCeElapsedRef.current = ceElapsedSeconds;
  }, [ceInEntryZone, ceElapsedSeconds]);
  
  const prevPeElapsedRef = useRef(0);
  const peCancelledRef = useRef(false);
  useEffect(() => {
    if (!peInEntryZone && prevPeElapsedRef.current > 0 && prevPeElapsedRef.current < CONFIRMATION_TIME && !peCancelledRef.current) {
      peCancelledRef.current = true;
    }
    if (peInEntryZone) {
      peCancelledRef.current = false;
    }
    prevPeElapsedRef.current = peElapsedSeconds;
  }, [peInEntryZone, peElapsedSeconds]);
  
  // Sync ref state to cancelledSignal state via data refresh (every 10 seconds)
  useEffect(() => {
    const checkCancellation = () => {
      if (ceCancelledRef.current) {
        setCancelledSignal('CE');
        ceCancelledRef.current = false;
      } else if (peCancelledRef.current) {
        setCancelledSignal('PE');
        peCancelledRef.current = false;
      }
    };
    checkCancellation();
    const interval = setInterval(checkCancellation, 1000);
    return () => clearInterval(interval);
  }, []);
  
  // Auto-clear cancellation after 30 seconds
  useEffect(() => {
    if (cancelledSignal) {
      const timeout = setTimeout(() => setCancelledSignal(null), 30000);
      return () => clearTimeout(timeout);
    }
  }, [cancelledSignal]);
  
  const formatTimeRemaining = (elapsed) => {
    const remaining = Math.max(0, CONFIRMATION_TIME - elapsed);
    const mins = Math.floor(remaining / 60);
    const secs = remaining % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const getScalpingData = () => {
    const price = trendData.price;
    const sma9 = trendData.sma9;
    const rsi = technicalData?.rsi || 50;
    const dayHigh = technicalData?.dayHigh || price * 1.005;
    const dayLow = technicalData?.dayLow || price * 0.995;
    const dayRange = dayHigh - dayLow;
    const scalp_sl = Math.round(dayRange * 0.3);
    const scalp_target = Math.round(dayRange * 0.5);
    
    let scalpSignal = 'NO TRADE';
    let scalpDirection = 'Neutral';
    let scalpEntry = price;
    let scalpSL = price - scalp_sl;
    let scalpTarget = price + scalp_target;
    let optionType = '-';
    let scalpReason = '';
    let confirmationStatus = null;
    let signalStrength = 'weak';
    let timeInZone = 0;
    let timeRemaining = '5:00';
    
    // Show cancelled state
    if (cancelledSignal) {
      scalpSignal = `🚫 ${cancelledSignal} CANCELLED`;
      scalpDirection = 'Cancelled';
      optionType = '-';
      scalpEntry = 0;
      scalpSL = 0;
      scalpTarget = 0;
      scalpReason = `${cancelledSignal} confirmation cancelled - Market direction changed during 5-min hold. Moving to NEUTRAL. Wait for new setup.`;
      signalStrength = 'none';
      confirmationStatus = 'cancelled';
      return { 
        scalpSignal, scalpDirection, scalpEntry, scalpSL, scalpTarget, optionType, 
        scalp_sl, scalp_target, scalpReason, confirmationStatus, timeInZone, timeRemaining,
        signalStrength, trend: 'NEUTRAL', distanceFromSMA: trendData.distanceFromSMA, 
        absDistance: trendData.absDistance
      };
    }
    
    if (trendData.trend === 'BULLISH') {
      optionType = 'CE';
      
      if (ceInEntryZone) {
        timeInZone = ceTimeInZone;
        timeRemaining = formatTimeRemaining(ceElapsedSeconds);
        
        if (ceIsConfirmed) {
          scalpSignal = 'BUY CE NOW';
          scalpDirection = 'Long (Confirmed)';
          scalpEntry = Math.round(price);
          scalpSL = scalpEntry - scalp_sl;
          scalpTarget = scalpEntry + scalp_target;
          scalpReason = `Price held within ${CE_ENTRY_TOLERANCE} pts of 9 SMA for 5 mins. EXECUTE CE trade!`;
          confirmationStatus = 'confirmed';
          signalStrength = 'strong';
        } else {
          scalpSignal = 'CE CONFIRMING...';
          scalpDirection = 'Long (Confirming)';
          scalpEntry = Math.round(price);
          scalpSL = scalpEntry - scalp_sl;
          scalpTarget = scalpEntry + scalp_target;
          scalpReason = `Price in CE entry zone (${Math.round(trendData.absDistance)} pts from SMA). Holding for 5-min confirmation...`;
          confirmationStatus = 'confirming';
          signalStrength = 'medium';
        }
      } else if (rsi > 75) {
        scalpSignal = 'WAIT - OVERBOUGHT';
        scalpDirection = 'Long (Wait)';
        scalpEntry = Math.round(sma9);
        scalpSL = scalpEntry - scalp_sl;
        scalpTarget = Math.round(dayHigh);
        scalpReason = `RSI ${rsi.toFixed(0)} overbought. Wait for price to pull back to 9 SMA (₹${Math.round(sma9)})`;
        signalStrength = 'weak';
      } else {
        scalpSignal = 'WAIT FOR DIP';
        scalpDirection = 'Long (Wait)';
        scalpEntry = Math.round(sma9);
        scalpSL = scalpEntry - scalp_sl;
        scalpTarget = scalpEntry + scalp_target;
        scalpReason = `Bullish trend. Wait for price to dip within ${CE_ENTRY_TOLERANCE} pts of 9 SMA (₹${Math.round(sma9)})`;
        signalStrength = 'weak';
      }
    } else if (trendData.trend === 'BEARISH') {
      optionType = 'PE';
      const distanceBelow = Math.abs(trendData.distanceFromSMA);
      
      if (peInEntryZone) {
        timeInZone = peTimeInZone;
        timeRemaining = formatTimeRemaining(peElapsedSeconds);
        
        if (peIsConfirmed) {
          const strengthLevel = distanceBelow >= 50 ? 'STRONG' : distanceBelow >= 35 ? 'GOOD' : 'MODERATE';
          scalpSignal = `BUY PE NOW (${strengthLevel})`;
          scalpDirection = 'Short (Confirmed)';
          scalpEntry = Math.round(price);
          scalpSL = scalpEntry + scalp_sl;
          scalpTarget = scalpEntry - scalp_target;
          scalpReason = `Price held ${Math.round(distanceBelow)} pts below 9 SMA for 5 mins. ${strengthLevel} bearish - EXECUTE PE trade!`;
          confirmationStatus = 'confirmed';
          signalStrength = distanceBelow >= 40 ? 'strong' : 'medium';
        } else {
          const strengthLevel = distanceBelow >= 50 ? 'STRONG' : distanceBelow >= 35 ? 'GOOD' : 'MODERATE';
          scalpSignal = `PE CONFIRMING (${strengthLevel})...`;
          scalpDirection = 'Short (Confirming)';
          scalpEntry = Math.round(price);
          scalpSL = scalpEntry + scalp_sl;
          scalpTarget = scalpEntry - scalp_target;
          scalpReason = `Price ${Math.round(distanceBelow)} pts below SMA. Holding for 5-min confirmation...`;
          confirmationStatus = 'confirming';
          signalStrength = 'medium';
        }
      } else {
        scalpSignal = 'PE BUILDING...';
        scalpDirection = 'Short (Building)';
        scalpEntry = Math.round(sma9 - PE_MIN_DISTANCE);
        scalpSL = Math.round(sma9) + 15;
        scalpTarget = scalpEntry - scalp_target;
        scalpReason = `Price ${Math.round(distanceBelow)} pts below SMA. Need ${PE_MIN_DISTANCE}+ pts below for PE entry.`;
        signalStrength = 'weak';
      }
    } else {
      optionType = '-';
      scalpSignal = 'NO TRADE (NEUTRAL)';
      scalpDirection = 'Neutral';
      scalpEntry = Math.round(sma9);
      scalpSL = 0;
      scalpTarget = 0;
      scalpReason = `Price in neutral zone (within ±${TREND_BUFFER} pts of SMA). No CE or PE trades. Wait for clear trend breakout.`;
      signalStrength = 'none';
    }
    
    return { 
      scalpSignal, scalpDirection, scalpEntry, scalpSL, scalpTarget, optionType, 
      scalp_sl, scalp_target, scalpReason, confirmationStatus, timeInZone, timeRemaining,
      signalStrength, trend: trendData.trend, distanceFromSMA: trendData.distanceFromSMA, 
      absDistance: trendData.absDistance
    };
  };

  const scalpData = getScalpingData();

  const getCardBackground = () => {
    if (scalpData.confirmationStatus === 'cancelled') {
      return 'linear-gradient(135deg, #7c2d12 0%, #9a3412 100%)';
    }
    if (scalpData.scalpSignal.includes('NOW')) {
      return scalpData.optionType === 'CE' 
        ? 'linear-gradient(135deg, #14532d 0%, #166534 100%)'
        : 'linear-gradient(135deg, #7f1d1d 0%, #991b1b 100%)';
    }
    if (scalpData.confirmationStatus === 'confirming') {
      return 'linear-gradient(135deg, #713f12 0%, #854d0e 100%)';
    }
    if (scalpData.trend === 'NEUTRAL') {
      return 'linear-gradient(135deg, #374151 0%, #4b5563 100%)';
    }
    return 'linear-gradient(135deg, #1e293b 0%, #334155 100%)';
  };

  const getCardBorder = () => {
    if (scalpData.confirmationStatus === 'cancelled') return '2px solid #f97316';
    if (scalpData.scalpSignal.includes('NOW')) {
      return scalpData.optionType === 'CE' ? '2px solid #22c55e' : '2px solid #ef4444';
    }
    if (scalpData.confirmationStatus === 'confirming') return '2px solid #eab308';
    return '1px solid #475569';
  };

  return (
    <div className="tab-content options-tab">
      <div className="options-header">
        <h2 className="section-title">📊 NIFTY 50 Scalping Analysis</h2>
        <div className="options-controls">
          <select value={timeframe} onChange={(e) => setTimeframe(e.target.value)} className="symbol-select">
            <option value="1H">1 Hour</option>
            <option value="15m">15 Minutes</option>
            <option value="4H">4 Hours</option>
            <option value="1D">Daily</option>
          </select>
          <button onClick={onRefresh} className="refresh-btn" style={{marginLeft: '0.5rem', padding: '0.5rem 1rem', borderRadius: '0.375rem', border: '1px solid var(--border)', background: 'var(--bg-secondary)', cursor: 'pointer'}}>
            Refresh
          </button>
        </div>
      </div>

      {loading ? (
        <div className="loading-options"><div className="skeleton-chart"></div></div>
      ) : (
        <div className="options-content">
          <div style={{marginBottom: '1.5rem'}}>
            <div style={{background: getCardBackground(), borderRadius: '0.75rem', padding: '1.5rem', border: getCardBorder(), color: '#fff'}}>
              <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.75rem'}}>
                <h3 style={{fontSize: '1.125rem', fontWeight: 600, display: 'flex', alignItems: 'center', gap: '0.5rem', margin: 0}}>
                  ⚡ Scalping Signal (5-15 min)
                </h3>
                <div style={{display: 'flex', gap: '0.5rem', alignItems: 'center'}}>
                  <span style={{
                    padding: '0.2rem 0.5rem', borderRadius: '0.25rem', fontSize: '0.75rem',
                    background: scalpData.trend === 'BULLISH' ? 'rgba(34, 197, 94, 0.2)' : scalpData.trend === 'BEARISH' ? 'rgba(239, 68, 68, 0.2)' : 'rgba(156, 163, 175, 0.2)',
                    color: scalpData.trend === 'BULLISH' ? '#4ade80' : scalpData.trend === 'BEARISH' ? '#f87171' : '#9ca3af'
                  }}>
                    {scalpData.trend === 'BULLISH' ? '📈 BULLISH' : scalpData.trend === 'BEARISH' ? '📉 BEARISH' : '➡️ NEUTRAL'}
                  </span>
                  <span style={{
                    padding: '0.25rem 0.75rem', borderRadius: '9999px', fontSize: '0.875rem', fontWeight: 700,
                    background: scalpData.confirmationStatus === 'cancelled' ? '#f97316' : scalpData.signalStrength === 'strong' ? (scalpData.optionType === 'CE' ? '#22c55e' : '#ef4444') : scalpData.signalStrength === 'medium' ? '#eab308' : 'rgba(156, 163, 175, 0.3)',
                    color: scalpData.signalStrength === 'none' && scalpData.confirmationStatus !== 'cancelled' ? '#9ca3af' : '#fff',
                    animation: scalpData.signalStrength === 'strong' ? 'pulse 2s infinite' : 'none'
                  }}>
                    {scalpData.confirmationStatus === 'cancelled' ? 'CANCELLED' : scalpData.optionType !== '-' ? scalpData.optionType : 'WAIT'}
                  </span>
                </div>
              </div>

              <div style={{
                marginBottom: '1rem', padding: '1rem', 
                background: scalpData.confirmationStatus === 'cancelled' ? 'rgba(249, 115, 22, 0.3)' : scalpData.signalStrength === 'strong' ? (scalpData.optionType === 'CE' ? 'rgba(34, 197, 94, 0.3)' : 'rgba(239, 68, 68, 0.3)') : scalpData.signalStrength === 'medium' ? 'rgba(234, 179, 8, 0.3)' : 'rgba(255,255,255,0.05)', 
                borderRadius: '0.5rem', 
                border: scalpData.confirmationStatus === 'cancelled' ? '1px solid #f97316' : scalpData.signalStrength === 'strong' ? (scalpData.optionType === 'CE' ? '1px solid #22c55e' : '1px solid #ef4444') : scalpData.signalStrength === 'medium' ? '1px solid #eab308' : '1px solid rgba(255,255,255,0.1)',
                textAlign: 'center'
              }}>
                <strong style={{fontSize: '1.25rem', display: 'block', marginBottom: '0.5rem'}}>{scalpData.scalpSignal}</strong>
                
                {scalpData.confirmationStatus === 'confirming' && (
                  <>
                    <div style={{fontSize: '2rem', fontWeight: 700, margin: '0.5rem 0', fontFamily: 'monospace'}}>{scalpData.timeRemaining}</div>
                    <div style={{marginTop: '0.5rem', height: '6px', background: 'rgba(255,255,255,0.2)', borderRadius: '3px', overflow: 'hidden'}}>
                      <div style={{height: '100%', width: `${(scalpData.timeInZone / 300) * 100}%`, background: '#eab308', transition: 'width 1s linear'}}></div>
                    </div>
                    <div style={{fontSize: '0.75rem', marginTop: '0.5rem', color: 'rgba(255,255,255,0.6)'}}>
                      ⚠️ If market direction changes, confirmation will be cancelled
                    </div>
                  </>
                )}
                
                <div style={{fontSize: '0.875rem', marginTop: '0.5rem', color: 'rgba(255,255,255,0.8)'}}>{scalpData.scalpReason}</div>
              </div>

              <div style={{marginBottom: '1rem', padding: '0.75rem', background: 'rgba(255,255,255,0.05)', borderRadius: '0.5rem', fontSize: '0.8rem'}}>
                <strong style={{display: 'block', marginBottom: '0.5rem'}}>📋 Trading Rules:</strong>
                <div style={{display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.5rem'}}>
                  <div style={{color: '#4ade80'}}><strong>CE Entry:</strong> Within {CE_ENTRY_TOLERANCE} pts of SMA + 5-min hold</div>
                  <div style={{color: '#f87171'}}><strong>PE Entry:</strong> {PE_MIN_DISTANCE}+ pts BELOW SMA + 5-min hold</div>
                </div>
                <div style={{marginTop: '0.5rem', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.5rem'}}>
                  <div style={{color: '#9ca3af'}}><strong>Neutral Zone:</strong> ±{TREND_BUFFER} pts = No trades</div>
                  <div style={{color: '#f97316'}}><strong>Direction Change:</strong> Cancels 5-min hold → NEUTRAL</div>
                </div>
              </div>

              <div style={{display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '0.75rem', marginBottom: '1rem'}}>
                <div style={{background: 'rgba(255,255,255,0.05)', padding: '0.75rem', borderRadius: '0.5rem', textAlign: 'center'}}>
                  <div style={{fontSize: '0.7rem', color: '#94a3b8', marginBottom: '0.25rem'}}>Current Price</div>
                  <div style={{fontWeight: 600, fontSize: '1rem'}}>₹{trendData.price?.toLocaleString()}</div>
                </div>
                <div style={{background: 'rgba(255,255,255,0.05)', padding: '0.75rem', borderRadius: '0.5rem', textAlign: 'center'}}>
                  <div style={{fontSize: '0.7rem', color: '#94a3b8', marginBottom: '0.25rem'}}>9 SMA</div>
                  <div style={{fontWeight: 600, fontSize: '1rem'}}>₹{trendData.sma9?.toLocaleString()}</div>
                </div>
                <div style={{background: 'rgba(255,255,255,0.05)', padding: '0.75rem', borderRadius: '0.5rem', textAlign: 'center'}}>
                  <div style={{fontSize: '0.7rem', color: '#94a3b8', marginBottom: '0.25rem'}}>Distance</div>
                  <div style={{fontWeight: 600, fontSize: '1rem', color: scalpData.distanceFromSMA > 0 ? '#4ade80' : scalpData.distanceFromSMA < 0 ? '#f87171' : '#9ca3af'}}>
                    {scalpData.distanceFromSMA > 0 ? '+' : ''}{Math.round(scalpData.distanceFromSMA)} pts
                  </div>
                </div>
                <div style={{background: 'rgba(255,255,255,0.05)', padding: '0.75rem', borderRadius: '0.5rem', textAlign: 'center'}}>
                  <div style={{fontSize: '0.7rem', color: '#94a3b8', marginBottom: '0.25rem'}}>RSI</div>
                  <div style={{fontWeight: 600, fontSize: '1rem', color: technicalData?.rsi > 70 ? '#f87171' : technicalData?.rsi < 30 ? '#4ade80' : '#fbbf24'}}>
                    {technicalData?.rsi?.toFixed(1)}
                  </div>
                </div>
              </div>
              
              {scalpData.optionType !== '-' && scalpData.confirmationStatus !== 'cancelled' && (
                <div style={{display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '0.75rem', marginBottom: '1rem'}}>
                  <div style={{background: 'rgba(59, 130, 246, 0.1)', padding: '0.75rem', borderRadius: '0.5rem', borderLeft: '3px solid #3b82f6'}}>
                    <div style={{fontSize: '0.75rem', color: '#93c5fd', marginBottom: '0.25rem'}}>Entry</div>
                    <div style={{fontWeight: 600}}>₹{scalpData.scalpEntry?.toLocaleString()}</div>
                  </div>
                  <div style={{background: 'rgba(34, 197, 94, 0.1)', padding: '0.75rem', borderRadius: '0.5rem', borderLeft: '3px solid #22c55e'}}>
                    <div style={{fontSize: '0.75rem', color: '#4ade80', marginBottom: '0.25rem'}}>Target</div>
                    <div style={{fontWeight: 600}}>₹{scalpData.scalpTarget?.toLocaleString()}</div>
                    <div style={{fontSize: '0.7rem', color: '#94a3b8'}}>+{scalpData.scalp_target} pts</div>
                  </div>
                  <div style={{background: 'rgba(239, 68, 68, 0.1)', padding: '0.75rem', borderRadius: '0.5rem', borderLeft: '3px solid #ef4444'}}>
                    <div style={{fontSize: '0.75rem', color: '#f87171', marginBottom: '0.25rem'}}>Stop Loss</div>
                    <div style={{fontWeight: 600}}>₹{scalpData.scalpSL?.toLocaleString()}</div>
                    <div style={{fontSize: '0.7rem', color: '#94a3b8'}}>{scalpData.scalp_sl} pts risk</div>
                  </div>
                </div>
              )}
            </div>
          </div>

          <div className="analysis-grid" style={{display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '1.5rem'}}>
            <div className="analysis-card" style={{background: 'var(--bg-card)', borderRadius: '0.75rem', padding: '1.5rem', border: '1px solid var(--border)'}}>
              <h3 style={{fontSize: '1.125rem', fontWeight: 600, marginBottom: '1rem', display: 'flex', alignItems: 'center', gap: '0.5rem'}}>
                📈 Technical Indicators ({timeframe})
              </h3>
              <div className="indicator-list" style={{display: 'flex', flexDirection: 'column', gap: '1rem'}}>
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0.75rem', background: 'var(--bg-primary)', borderRadius: '0.5rem'}}>
                  <span style={{color: 'var(--text-secondary)'}}>Current Price</span>
                  <span style={{fontWeight: 600, fontSize: '1.25rem'}}>₹{technicalData?.currentPrice?.toLocaleString()}</span>
                </div>
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0.75rem', background: 'var(--bg-primary)', borderRadius: '0.5rem'}}>
                  <span style={{color: 'var(--text-secondary)'}}>9 SMA</span>
                  <div style={{textAlign: 'right'}}>
                    <span style={{fontWeight: 600}}>₹{technicalData?.sma9?.toLocaleString()}</span>
                    <span style={{marginLeft: '0.5rem', color: technicalData?.currentPrice > technicalData?.sma9 ? '#22c55e' : '#ef4444', fontSize: '0.875rem'}}>
                      ({technicalData?.currentPrice > technicalData?.sma9 ? 'Above' : 'Below'})
                    </span>
                  </div>
                </div>
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0.75rem', background: 'var(--bg-primary)', borderRadius: '0.5rem'}}>
                  <span style={{color: 'var(--text-secondary)'}}>20 SMA</span>
                  <div style={{textAlign: 'right'}}>
                    <span style={{fontWeight: 600}}>₹{technicalData?.sma20?.toLocaleString()}</span>
                    <span style={{marginLeft: '0.5rem', color: technicalData?.currentPrice > technicalData?.sma20 ? '#22c55e' : '#ef4444', fontSize: '0.875rem'}}>
                      ({technicalData?.currentPrice > technicalData?.sma20 ? 'Above' : 'Below'})
                    </span>
                  </div>
                </div>
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0.75rem', background: 'var(--bg-primary)', borderRadius: '0.5rem'}}>
                  <span style={{color: 'var(--text-secondary)'}}>RSI (14)</span>
                  <div style={{textAlign: 'right'}}>
                    <span style={{fontWeight: 600}}>{technicalData?.rsi?.toFixed(2)}</span>
                    <span style={{marginLeft: '0.5rem', color: technicalData?.rsi > 70 ? '#ef4444' : technicalData?.rsi < 30 ? '#22c55e' : '#eab308', fontSize: '0.875rem'}}>
                      ({technicalData?.rsi > 70 ? 'Overbought' : technicalData?.rsi < 30 ? 'Oversold' : 'Neutral'})
                    </span>
                  </div>
                </div>
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0.75rem', background: 'var(--bg-primary)', borderRadius: '0.5rem'}}>
                  <span style={{color: 'var(--text-secondary)'}}>Trend</span>
                  <span style={{fontWeight: 600, color: technicalData?.trend === 'Bullish' ? '#22c55e' : technicalData?.trend === 'Bearish' ? '#ef4444' : '#eab308'}}>
                    {getTrendIcon(technicalData?.trend)} {technicalData?.trend}
                  </span>
                </div>
              </div>
            </div>

            <div className="analysis-card" style={{background: 'var(--bg-card)', borderRadius: '0.75rem', padding: '1.5rem', border: '1px solid var(--border)'}}>
              <h3 style={{fontSize: '1.125rem', fontWeight: 600, marginBottom: '1rem', display: 'flex', alignItems: 'center', gap: '0.5rem'}}>🎯 Weekly Pivot Points</h3>
              <div style={{display: 'flex', flexDirection: 'column', gap: '0.75rem'}}>
                <div style={{padding: '0.5rem', background: 'rgba(239, 68, 68, 0.1)', borderRadius: '0.5rem', borderLeft: '3px solid #ef4444'}}>
                  <div style={{fontSize: '0.75rem', color: '#ef4444', marginBottom: '0.25rem'}}>R3</div>
                  <div style={{fontWeight: 600}}>₹{pivotData?.r3?.toLocaleString()}</div>
                </div>
                <div style={{padding: '0.5rem', background: 'rgba(239, 68, 68, 0.08)', borderRadius: '0.5rem', borderLeft: '3px solid #f97316'}}>
                  <div style={{fontSize: '0.75rem', color: '#f97316', marginBottom: '0.25rem'}}>R2</div>
                  <div style={{fontWeight: 600}}>₹{pivotData?.r2?.toLocaleString()}</div>
                </div>
                <div style={{padding: '0.5rem', background: 'rgba(239, 68, 68, 0.05)', borderRadius: '0.5rem', borderLeft: '3px solid #fb923c'}}>
                  <div style={{fontSize: '0.75rem', color: '#fb923c', marginBottom: '0.25rem'}}>R1</div>
                  <div style={{fontWeight: 600}}>₹{pivotData?.r1?.toLocaleString()}</div>
                </div>
                <div style={{padding: '0.75rem', background: 'rgba(59, 130, 246, 0.1)', borderRadius: '0.5rem', borderLeft: '3px solid #3b82f6'}}>
                  <div style={{fontSize: '0.75rem', color: '#3b82f6', marginBottom: '0.25rem'}}>Pivot</div>
                  <div style={{fontWeight: 700, fontSize: '1.125rem'}}>₹{pivotData?.pivot?.toLocaleString()}</div>
                </div>
                <div style={{padding: '0.5rem', background: 'rgba(34, 197, 94, 0.05)', borderRadius: '0.5rem', borderLeft: '3px solid #4ade80'}}>
                  <div style={{fontSize: '0.75rem', color: '#4ade80', marginBottom: '0.25rem'}}>S1</div>
                  <div style={{fontWeight: 600}}>₹{pivotData?.s1?.toLocaleString()}</div>
                </div>
                <div style={{padding: '0.5rem', background: 'rgba(34, 197, 94, 0.08)', borderRadius: '0.5rem', borderLeft: '3px solid #22c55e'}}>
                  <div style={{fontSize: '0.75rem', color: '#22c55e', marginBottom: '0.25rem'}}>S2</div>
                  <div style={{fontWeight: 600}}>₹{pivotData?.s2?.toLocaleString()}</div>
                </div>
                <div style={{padding: '0.5rem', background: 'rgba(34, 197, 94, 0.1)', borderRadius: '0.5rem', borderLeft: '3px solid #16a34a'}}>
                  <div style={{fontSize: '0.75rem', color: '#16a34a', marginBottom: '0.25rem'}}>S3</div>
                  <div style={{fontWeight: 600}}>₹{pivotData?.s3?.toLocaleString()}</div>
                </div>
              </div>
            </div>
          </div>

          <div style={{marginTop: '1.5rem', display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: '1rem'}}>
            <div style={{padding: '1rem', background: 'var(--bg-card)', borderRadius: '0.5rem', textAlign: 'center', border: '1px solid var(--border)'}}>
              <div style={{fontSize: '0.75rem', color: 'var(--text-secondary)'}}>Day High</div>
              <div style={{fontWeight: 600, color: '#22c55e'}}>₹{technicalData?.dayHigh?.toLocaleString()}</div>
            </div>
            <div style={{padding: '1rem', background: 'var(--bg-card)', borderRadius: '0.5rem', textAlign: 'center', border: '1px solid var(--border)'}}>
              <div style={{fontSize: '0.75rem', color: 'var(--text-secondary)'}}>Day Low</div>
              <div style={{fontWeight: 600, color: '#ef4444'}}>₹{technicalData?.dayLow?.toLocaleString()}</div>
            </div>
            <div style={{padding: '1rem', background: 'var(--bg-card)', borderRadius: '0.5rem', textAlign: 'center', border: '1px solid var(--border)'}}>
              <div style={{fontSize: '0.75rem', color: 'var(--text-secondary)'}}>Prev Close</div>
              <div style={{fontWeight: 600}}>₹{technicalData?.previousClose?.toLocaleString()}</div>
            </div>
            <div style={{padding: '1rem', background: 'var(--bg-card)', borderRadius: '0.5rem', textAlign: 'center', border: '1px solid var(--border)'}}>
              <div style={{fontSize: '0.75rem', color: 'var(--text-secondary)'}}>Change</div>
              <div style={{fontWeight: 600, color: technicalData?.change >= 0 ? '#22c55e' : '#ef4444'}}>
                {technicalData?.change >= 0 ? '+' : ''}{technicalData?.pChange?.toFixed(2)}%
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default OptionsAnalysisTab;
