// Recommendations Tab Component

const RecommendationsTab = ({ recommendations, loading }) => {
  const getSignalColor = (signal) => {
    switch(signal) {
      case 'BUY': return 'signal-buy';
      case 'SELL': return 'signal-sell';
      case 'Weak BUY': return 'signal-weak-buy';
      case 'Weak SELL': return 'signal-weak-sell';
      default: return 'signal-hold';
    }
  };

  return (
    <div className="tab-content">
      <h2 className="section-title">
        🎯 Trading Recommendations
      </h2>
      <p className="section-subtitle">Based on RSI and 9 SMA (1H timeframe)</p>
      
      {loading ? (
        <div className="loading-table">
          {[...Array(10)].map((_, i) => (
            <div key={i} className="skeleton-row"></div>
          ))}
        </div>
      ) : (
        <div className="recommendations-table">
          <table>
            <thead>
              <tr>
                <th>Index</th>
                <th>Price</th>
                <th>Change</th>
                <th>RSI (14)</th>
                <th>9 SMA</th>
                <th>Trend</th>
                <th>Signal</th>
              </tr>
            </thead>
            <tbody>
              {recommendations.map((rec, i) => (
                <tr key={i} data-testid={`recommendation-${rec.symbol}`}>
                  <td className="index-name">{rec.name}</td>
                  <td>{rec.lastPrice?.toLocaleString()}</td>
                  <td className={rec.pChange >= 0 ? 'positive' : 'negative'}>
                    {rec.pChange >= 0 ? '+' : ''}{rec.pChange?.toFixed(2)}%
                  </td>
                  <td>
                    <span className={`rsi-value ${rec.rsi < 30 ? 'oversold' : rec.rsi > 70 ? 'overbought' : ''}`}>
                      {rec.rsi?.toFixed(1)}
                    </span>
                  </td>
                  <td>{rec.sma9?.toLocaleString()}</td>
                  <td>
                    <span className={`trend ${rec.trend?.toLowerCase()}`}>{rec.trend}</span>
                  </td>
                  <td>
                    <span className={`signal ${getSignalColor(rec.signal)}`}>{rec.signal}</span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default RecommendationsTab;
