// Sector Comparison Tab Component

const SectorComparisonTab = ({ indices, loading }) => {
  const nifty50 = indices.find(i => i.symbol === 'NIFTY 50' || i.name?.includes('Nifty 50'));
  const sortedByPerformance = [...indices]
    .filter(i => i.symbol !== 'NIFTY 50')
    .sort((a, b) => b.pChange - a.pChange);

  return (
    <div className="tab-content">
      <h2 className="section-title">📊 Sector Comparison vs Nifty 50</h2>
      
      {loading ? (
        <div className="loading-bars">
          {[...Array(10)].map((_, i) => (
            <div key={i} className="skeleton-bar"></div>
          ))}
        </div>
      ) : (
        <div className="comparison-chart">
          {sortedByPerformance.map((idx, i) => {
            const vsNifty = nifty50 ? (idx.pChange - nifty50.pChange) : 0;
            const barWidth = Math.min(Math.abs(vsNifty) * 20, 100);
            
            return (
              <div key={i} className="comparison-row" data-testid={`comparison-${idx.symbol}`}>
                <div className="comparison-label">
                  <span className="name">{idx.name}</span>
                  <span className={`change ${idx.pChange >= 0 ? 'positive' : 'negative'}`}>
                    {idx.pChange >= 0 ? '+' : ''}{idx.pChange?.toFixed(2)}%
                  </span>
                </div>
                <div className="comparison-bar-container">
                  <div className="zero-line"></div>
                  <div 
                    className={`comparison-bar ${vsNifty >= 0 ? 'outperform' : 'underperform'}`}
                    style={{ 
                      width: `${barWidth}%`,
                      [vsNifty >= 0 ? 'marginLeft' : 'marginRight']: '50%',
                      transform: vsNifty < 0 ? 'translateX(-100%)' : 'none'
                    }}
                  ></div>
                </div>
                <div className={`vs-value ${vsNifty >= 0 ? 'positive' : 'negative'}`}>
                  {vsNifty >= 0 ? '+' : ''}{vsNifty.toFixed(2)}%
                </div>
              </div>
            );
          })}
          
          {nifty50 && (
            <div className="nifty-baseline">
              <span>Nifty 50: {nifty50.pChange >= 0 ? '+' : ''}{nifty50.pChange?.toFixed(2)}%</span>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default SectorComparisonTab;
