// Ticker Component - Displays scrolling market data

const Ticker = ({ indices }) => {
  return (
    <div className="ticker-wrapper">
      <div className="ticker-content">
        {[...indices, ...indices].map((idx, i) => (
          <div key={i} className="ticker-item">
            <span className="ticker-name">{idx.name}</span>
            <span className="ticker-price">{idx.lastPrice?.toLocaleString()}</span>
            <span className={`ticker-change ${idx.pChange >= 0 ? 'positive' : 'negative'}`}>
              {idx.pChange >= 0 ? '+' : ''}{idx.pChange?.toFixed(2)}%
            </span>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Ticker;
