import { useState } from 'react';
import { TrendingUpIcon } from './Icons';

// Overview Tab Component
const OverviewTab = ({ indices, loading, topStocks, stockAnalysis, smaData, smaPeriod, smaTimeframe, onSmaChange, onFetchStocks, loadingStocks }) => {
  const [selectedSector, setSelectedSector] = useState(null);
  const [selectedStock, setSelectedStock] = useState(null);
  const [chartTimeframe, setChartTimeframe] = useState('6M');
  const [selectedChartIndex, setSelectedChartIndex] = useState('NIFTY 50');
  
  const sortedIndices = [...indices].sort((a, b) => b.pChange - a.pChange);
  const nifty50 = indices.find(i => i.symbol === 'NIFTY 50' || i.name?.includes('Nifty 50'));
  
  // Create a lookup map for SMA data
  const smaLookup = {};
  smaData.forEach(item => {
    smaLookup[item.symbol] = item;
  });

  // Handle sector selection - fetch stocks if not already loaded
  const handleSectorClick = (sector) => {
    if (selectedSector === sector) {
      setSelectedSector(null);
      setSelectedStock(null);
    } else {
      setSelectedSector(sector);
      setSelectedStock(null);
      // Fetch stocks if not already loaded
      if (!topStocks[sector] && onFetchStocks) {
        onFetchStocks(sector);
      }
    }
  };

  // Handle SMA timeframe change
  const handleSmaChange = async (period, timeframe) => {
    if (onSmaChange) {
      await onSmaChange(period, timeframe);
    }
  };

  // Get SMA label
  const getSmaLabel = () => {
    const unit = smaTimeframe === 'monthly' ? 'M' : 'D';
    return `${smaPeriod}${unit} SMA`;
  };
  
  // Get chart month labels based on timeframe
  const getChartLabels = () => {
    const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    const currentMonth = new Date().getMonth();
    
    if (chartTimeframe === '3M') {
      return months.slice(Math.max(0, currentMonth - 2), currentMonth + 1);
    } else if (chartTimeframe === '6M') {
      return months.slice(Math.max(0, currentMonth - 5), currentMonth + 1);
    } else {
      return months;
    }
  };
  
  return (
    <div className="tab-content">
      <div className="section-header-row" style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '1rem', marginBottom: '1rem'}}>
        <h2 className="section-title" style={{margin: 0}}>
          <TrendingUpIcon /> All Sectors Performance
        </h2>
        <div className="sma-selector" style={{display: 'flex', alignItems: 'center', gap: '0.5rem'}}>
          <label style={{fontSize: '0.875rem', color: 'var(--text-secondary)'}}>SMA:</label>
          <select 
            value={`${smaPeriod}-${smaTimeframe}`}
            onChange={(e) => {
              const [period, timeframe] = e.target.value.split('-');
              handleSmaChange(parseInt(period), timeframe);
            }}
            className="index-select"
            style={{padding: '0.375rem 0.5rem', fontSize: '0.875rem'}}
          >
            <option value="9-daily">9-Day</option>
            <option value="20-daily">20-Day</option>
            <option value="50-daily">50-Day</option>
            <option value="9-monthly">9-Month</option>
            <option value="20-monthly">20-Month (Bollinger)</option>
            <option value="50-monthly">50-Month</option>
          </select>
        </div>
      </div>
      
      {loading ? (
        <div className="loading-grid">
          {[...Array(12)].map((_, i) => (
            <div key={i} className="skeleton-card"></div>
          ))}
        </div>
      ) : (
        <>
          <div className="sectors-grid">
            {sortedIndices.map((idx, i) => {
              // Use vsNifty from SMA data if available, otherwise calculate
              const smaInfo = smaLookup[idx.symbol];
              const vsNifty = smaInfo?.vsNifty !== undefined 
                ? smaInfo.vsNifty 
                : (nifty50 && idx.symbol !== 'NIFTY 50' 
                    ? (idx.pChange - nifty50.pChange).toFixed(2) 
                    : null);
              
              return (
                <div key={i} className="sector-card" data-testid={`sector-card-${idx.symbol}`}>
                  <div className="sector-header">
                    <h3>{idx.name}</h3>
                    <span className={`badge ${idx.pChange >= 0 ? 'badge-green' : 'badge-red'}`}>
                      {idx.pChange >= 0 ? '+' : ''}{idx.pChange?.toFixed(2)}%
                    </span>
                  </div>
                  <div className="sector-price">{idx.lastPrice?.toLocaleString()}</div>
                  <div className={`sector-change ${idx.change >= 0 ? 'positive' : 'negative'}`}>
                    {idx.change >= 0 ? '+' : ''}{idx.change?.toFixed(2)}
                  </div>
                  {vsNifty !== null && idx.symbol !== 'NIFTY 50' && (
                    <div className="vs-nifty">
                      <span>vs Nifty 50</span>
                      <span className={parseFloat(vsNifty) >= 0 ? 'positive' : 'negative'}>
                        {parseFloat(vsNifty) >= 0 ? '+' : ''}{vsNifty}%
                      </span>
                    </div>
                  )}
                  <div className="sma-info">
                    <span>{getSmaLabel()}:</span>
                    <span className={`sma-diff ${smaInfo?.percentDiff >= 0 ? 'positive' : 'negative'}`}>
                      {smaInfo?.percentDiff >= 0 ? '+' : ''}{smaInfo?.percentDiff?.toFixed(2) || '0'}%
                    </span>
                  </div>
                  <div className={`sma-status ${smaInfo?.position?.toLowerCase().replace(' ', '-') || 'at-sma'}`}>
                    {smaInfo?.position || 'At SMA'} {smaInfo?.bandPosition === 'Overbought' && '🔴'} {smaInfo?.bandPosition === 'Oversold' && '🟢'}
                  </div>
                  
                  {/* Top Stocks Button */}
                  <button 
                    className="view-stocks-btn"
                    onClick={() => handleSectorClick(idx.symbol)}
                    data-testid={`view-stocks-${idx.symbol}`}
                  >
                    {loadingStocks?.[idx.symbol] ? 'Loading...' : selectedSector === idx.symbol ? 'Hide Stocks' : 'View Stocks'}
                  </button>
                </div>
              );
            })}
          </div>
          
          {/* Stock Analysis Modal/Panel - Shows when a sector is selected */}
          {selectedSector && (
            <div className="stocks-analysis-section">
              <div className="stocks-section-header">
                <h3>📊 {selectedSector} - Top Stocks Analysis {loadingStocks?.[selectedSector] && <span style={{fontSize: '0.875rem', color: 'var(--text-muted)'}}>(Loading live data...)</span>}</h3>
                <button 
                  className="close-btn"
                  onClick={() => {setSelectedSector(null); setSelectedStock(null);}}
                >
                  ✕
                </button>
              </div>
              
              {loadingStocks?.[selectedSector] ? (
                <div style={{padding: '2rem', textAlign: 'center', color: 'var(--text-secondary)'}}>
                  <div className="skeleton-chart" style={{height: '200px', marginBottom: '1rem'}}></div>
                  <p>Fetching live stock prices from Yahoo Finance...</p>
                </div>
              ) : !topStocks[selectedSector] || topStocks[selectedSector].length === 0 ? (
                <div style={{padding: '2rem', textAlign: 'center', color: 'var(--text-secondary)'}}>
                  <p>No stock data available for this sector.</p>
                </div>
              ) : (
              <>
              <div className="stocks-table-container">
                <table className="stocks-table">
                  <thead>
                    <tr>
                      <th>Stock</th>
                      <th>Price</th>
                      <th>Change</th>
                      <th>Signal</th>
                      <th style={{color: '#22c55e'}}>🎯 Target</th>
                      <th style={{color: '#ef4444'}}>🛑 Stop Loss</th>
                      <th>RSI</th>
                      <th>Action</th>
                    </tr>
                  </thead>
                  <tbody>
                    {topStocks[selectedSector].map((stock, si) => {
                      const analysis = stockAnalysis[stock.symbol] || {};
                      const currentPrice = stock.price || 0;
                      
                      // Calculate Target and Stop Loss based on signal and technicals
                      let target = '-';
                      let stopLoss = '-';
                      let targetPercent = 0;
                      let slPercent = 0;
                      
                      if (analysis.signal === 'BUY' || analysis.signal === 'Weak BUY') {
                        // For BUY: Target must be ABOVE current price
                        const targetPrice = currentPrice * 1.08; // 8% above CMP
                        target = `₹${targetPrice.toFixed(0)}`;
                        targetPercent = '8.0';
                        
                        // Stop loss: MUST be below CMP - use 5% below
                        const slPrice = currentPrice * 0.95;
                        stopLoss = `₹${slPrice.toFixed(0)}`;
                        slPercent = '-5.0';
                      } else if (analysis.signal === 'SELL' || analysis.signal === 'Weak SELL') {
                        // For SELL: Target must be BELOW current price
                        const targetPrice = currentPrice * 0.92; // 8% below CMP
                        target = `₹${targetPrice.toFixed(0)}`;
                        targetPercent = '-8.0';
                        
                        // Stop loss: MUST be above CMP - use 5% above
                        const slPrice = currentPrice * 1.05;
                        stopLoss = `₹${slPrice.toFixed(0)}`;
                        slPercent = '5.0';
                      } else {
                        // HOLD: Show breakout/breakdown levels
                        const breakoutLevel = currentPrice * 1.03; // 3% above for target
                        const breakdownLevel = currentPrice * 0.97; // 3% below for SL
                        target = `₹${breakoutLevel.toFixed(0)}`;
                        stopLoss = `₹${breakdownLevel.toFixed(0)}`;
                        targetPercent = '3.0';
                        slPercent = '-3.0';
                      }
                      
                      return (
                        <tr key={si} className={selectedStock === stock.symbol ? 'selected-row' : ''}>
                          <td className="stock-symbol">
                            <strong>{stock.symbol}</strong>
                            <div style={{fontSize: '0.7rem', color: 'var(--text-muted)'}}>{analysis.trend || '-'}</div>
                          </td>
                          <td>
                            <strong>₹{stock.price?.toLocaleString()}</strong>
                          </td>
                          <td className={stock.change >= 0 ? 'positive' : 'negative'}>
                            {stock.change >= 0 ? '+' : ''}{stock.change?.toFixed(2)}%
                          </td>
                          <td>
                            <span className={`signal-badge ${(analysis.signal || '').toLowerCase().replace(' ', '-')}`} style={{fontWeight: 600}}>
                              {analysis.signal || '-'}
                            </span>
                          </td>
                          <td style={{background: 'rgba(34, 197, 94, 0.08)'}}>
                            <div style={{fontWeight: 600, color: '#22c55e'}}>{target}</div>
                            <div style={{fontSize: '0.7rem', color: '#4ade80'}}>({targetPercent > 0 ? '+' : ''}{targetPercent}%)</div>
                          </td>
                          <td style={{background: 'rgba(239, 68, 68, 0.08)'}}>
                            <div style={{fontWeight: 600, color: '#ef4444'}}>{stopLoss}</div>
                            <div style={{fontSize: '0.7rem', color: '#f87171'}}>({slPercent}%)</div>
                          </td>
                          <td>
                            <span className={`rsi-badge ${analysis.rsi < 30 ? 'oversold' : analysis.rsi > 70 ? 'overbought' : ''}`}>
                              {analysis.rsi || '-'}
                            </span>
                          </td>
                          <td>
                            <button 
                              className="details-btn"
                              onClick={() => setSelectedStock(selectedStock === stock.symbol ? null : stock.symbol)}
                            >
                              {selectedStock === stock.symbol ? 'Hide' : 'Details'}
                            </button>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
              
              {/* Quick Trading Summary */}
              <div style={{marginTop: '1rem', padding: '1rem', background: 'var(--bg-primary)', borderRadius: '0.5rem', border: '1px solid var(--border)'}}>
                <h4 style={{margin: '0 0 0.75rem 0', fontSize: '0.9rem', fontWeight: 600}}>📋 Quick Trading Guide</h4>
                <div style={{display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '0.75rem', fontSize: '0.8rem'}}>
                  <div style={{padding: '0.5rem', background: 'rgba(34, 197, 94, 0.1)', borderRadius: '0.375rem', borderLeft: '3px solid #22c55e'}}>
                    <strong style={{color: '#22c55e'}}>BUY Signal:</strong>
                    <div style={{color: 'var(--text-secondary)', marginTop: '0.25rem'}}>Entry at CMP, Target at 52W High, SL 3% below 20-SMA</div>
                  </div>
                  <div style={{padding: '0.5rem', background: 'rgba(239, 68, 68, 0.1)', borderRadius: '0.375rem', borderLeft: '3px solid #ef4444'}}>
                    <strong style={{color: '#ef4444'}}>SELL Signal:</strong>
                    <div style={{color: 'var(--text-secondary)', marginTop: '0.25rem'}}>Exit longs, Target at 52W Low, SL 2% above 9-SMA</div>
                  </div>
                  <div style={{padding: '0.5rem', background: 'rgba(234, 179, 8, 0.1)', borderRadius: '0.375rem', borderLeft: '3px solid #eab308'}}>
                    <strong style={{color: '#eab308'}}>HOLD Signal:</strong>
                    <div style={{color: 'var(--text-secondary)', marginTop: '0.25rem'}}>Wait for breakout, Range: ±3% from current price</div>
                  </div>
                </div>
              </div>
              </>
              )}
              
              {/* Detailed Stock Analysis Panel */}
              {selectedStock && stockAnalysis[selectedStock] && (
                <div className="detailed-analysis-panel">
                  <h4>{selectedStock} - Detailed Analysis</h4>
                  <div style={{display: 'flex', flexDirection: 'row', gap: '2rem', marginBottom: '1rem'}}>
                    <div style={{flex: 1, background: 'var(--bg-card)', border: '1px solid var(--border-color)', borderRadius: '0.5rem', padding: '1rem'}}>
                      <h5 style={{fontSize: '0.9rem', marginBottom: '1rem', fontWeight: 600}}>📈 Technical Indicators</h5>
                      <div style={{display: 'flex', flexDirection: 'column', gap: '0.5rem'}}>
                        <div style={{display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0.75rem', background: 'var(--bg-secondary)', borderRadius: '0.375rem'}}>
                          <span style={{color: 'var(--text-secondary)'}}>RSI (14)</span>
                          <span style={{fontWeight: 600}} className={stockAnalysis[selectedStock].rsi < 30 ? 'oversold' : stockAnalysis[selectedStock].rsi > 70 ? 'overbought' : ''}>
                            {stockAnalysis[selectedStock].rsi}
                          </span>
                        </div>
                        <div style={{display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0.75rem', background: 'var(--bg-secondary)', borderRadius: '0.375rem'}}>
                          <span style={{color: 'var(--text-secondary)'}}>9 SMA</span>
                          <span style={{fontWeight: 600}}>₹{stockAnalysis[selectedStock].sma9?.toLocaleString()}</span>
                        </div>
                        <div style={{display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0.75rem', background: 'var(--bg-secondary)', borderRadius: '0.375rem'}}>
                          <span style={{color: 'var(--text-secondary)'}}>20 SMA</span>
                          <span style={{fontWeight: 600}}>₹{stockAnalysis[selectedStock].sma20?.toLocaleString()}</span>
                        </div>
                        <div style={{display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0.75rem', background: 'var(--bg-secondary)', borderRadius: '0.375rem'}}>
                          <span style={{color: 'var(--text-secondary)'}}>MACD</span>
                          <span style={{fontWeight: 600}} className={stockAnalysis[selectedStock].macd >= 0 ? 'positive' : 'negative'}>
                            {stockAnalysis[selectedStock].macd}
                          </span>
                        </div>
                        <div style={{display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0.75rem', background: 'var(--bg-secondary)', borderRadius: '0.375rem'}}>
                          <span style={{color: 'var(--text-secondary)'}}>Signal</span>
                          <span className={`signal-badge ${(stockAnalysis[selectedStock].signal || '').toLowerCase().replace(' ', '-')}`}>
                            {stockAnalysis[selectedStock].signal}
                          </span>
                        </div>
                        <div style={{display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0.75rem', background: 'var(--bg-secondary)', borderRadius: '0.375rem'}}>
                          <span style={{color: 'var(--text-secondary)'}}>Trend</span>
                          <span className={`trend-badge ${(stockAnalysis[selectedStock].trend || '').toLowerCase()}`}>
                            {stockAnalysis[selectedStock].trend}
                          </span>
                        </div>
                      </div>
                    </div>
                    
                    <div style={{flex: 1, background: 'var(--bg-card)', border: '1px solid var(--border-color)', borderRadius: '0.5rem', padding: '1rem'}}>
                      <h5 style={{fontSize: '0.9rem', marginBottom: '1rem', fontWeight: 600}}>📊 Fundamentals</h5>
                      <div style={{display: 'flex', flexDirection: 'column', gap: '0.5rem'}}>
                        <div style={{display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0.75rem', background: 'var(--bg-secondary)', borderRadius: '0.375rem'}}>
                          <span style={{color: 'var(--text-secondary)'}}>P/E Ratio</span>
                          <span style={{fontWeight: 600}}>{stockAnalysis[selectedStock].pe}</span>
                        </div>
                        <div style={{display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0.75rem', background: 'var(--bg-secondary)', borderRadius: '0.375rem'}}>
                          <span style={{color: 'var(--text-secondary)'}}>Market Cap</span>
                          <span style={{fontWeight: 600}}>{stockAnalysis[selectedStock].marketCap}</span>
                        </div>
                        <div style={{display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0.75rem', background: 'var(--bg-secondary)', borderRadius: '0.375rem'}}>
                          <span style={{color: 'var(--text-secondary)'}}>EPS</span>
                          <span style={{fontWeight: 600}}>₹{stockAnalysis[selectedStock].eps}</span>
                        </div>
                        <div style={{display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0.75rem', background: 'var(--bg-secondary)', borderRadius: '0.375rem'}}>
                          <span style={{color: 'var(--text-secondary)'}}>Book Value</span>
                          <span style={{fontWeight: 600}}>₹{stockAnalysis[selectedStock].bookValue}</span>
                        </div>
                        <div style={{display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0.75rem', background: 'var(--bg-secondary)', borderRadius: '0.375rem'}}>
                          <span style={{color: 'var(--text-secondary)'}}>Div Yield</span>
                          <span style={{fontWeight: 600}}>{stockAnalysis[selectedStock].divYield}%</span>
                        </div>
                        <div style={{display: 'flex', justifyContent: 'space-between', padding: '0.5rem 0.75rem', background: 'var(--bg-secondary)', borderRadius: '0.375rem'}}>
                          <span style={{color: 'var(--text-secondary)'}}>52W Range</span>
                          <span style={{fontWeight: 600}}>₹{stockAnalysis[selectedStock].low52w} - ₹{stockAnalysis[selectedStock].high52w}</span>
                        </div>
                      </div>
                    </div>
                  </div>
                  
                  {/* Trading Levels - Target & Stop Loss */}
                  <div style={{
                    background: 'linear-gradient(135deg, #1e293b 0%, #334155 100%)',
                    borderRadius: '0.75rem',
                    padding: '1.25rem',
                    marginBottom: '1rem',
                    color: '#fff'
                  }}>
                    <h5 style={{fontSize: '1rem', marginBottom: '1rem', fontWeight: 700, display: 'flex', alignItems: 'center', gap: '0.5rem'}}>
                      🎯 Trading Levels for {selectedStock}
                      <span className={`signal-badge ${(stockAnalysis[selectedStock].signal || '').toLowerCase().replace(' ', '-')}`} style={{marginLeft: 'auto', fontSize: '0.875rem'}}>
                        {stockAnalysis[selectedStock].signal}
                      </span>
                    </h5>
                    
                    <div style={{display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '1rem', marginBottom: '1rem'}}>
                      {/* Entry Price */}
                      <div style={{background: 'rgba(59, 130, 246, 0.2)', padding: '1rem', borderRadius: '0.5rem', borderLeft: '4px solid #3b82f6', textAlign: 'center'}}>
                        <div style={{fontSize: '0.75rem', color: '#93c5fd', marginBottom: '0.25rem'}}>Entry Price</div>
                        <div style={{fontSize: '1.25rem', fontWeight: 700}}>
                          ₹{(() => {
                            const stock = topStocks[selectedSector]?.find(s => s.symbol === selectedStock);
                            return stock?.price?.toLocaleString() || '-';
                          })()}
                        </div>
                        <div style={{fontSize: '0.7rem', color: '#94a3b8'}}>Current Market Price</div>
                      </div>
                      
                      {/* Target 1 */}
                      <div style={{background: 'rgba(34, 197, 94, 0.2)', padding: '1rem', borderRadius: '0.5rem', borderLeft: '4px solid #22c55e', textAlign: 'center'}}>
                        <div style={{fontSize: '0.75rem', color: '#86efac', marginBottom: '0.25rem'}}>Target 1</div>
                        <div style={{fontSize: '1.25rem', fontWeight: 700, color: '#4ade80'}}>
                          ₹{(() => {
                            const stock = topStocks[selectedSector]?.find(s => s.symbol === selectedStock);
                            const cmp = stock?.price || 0;
                            if (stockAnalysis[selectedStock].signal === 'BUY' || stockAnalysis[selectedStock].signal === 'Weak BUY' || stockAnalysis[selectedStock].signal === 'HOLD') {
                              return (cmp * 1.05).toFixed(0);
                            } else {
                              return (cmp * 0.95).toFixed(0);
                            }
                          })()}
                        </div>
                        <div style={{fontSize: '0.7rem', color: '#94a3b8'}}>
                          {(stockAnalysis[selectedStock].signal === 'BUY' || stockAnalysis[selectedStock].signal === 'Weak BUY') ? '+5% from CMP' : '-5% from CMP'}
                        </div>
                      </div>
                      
                      {/* Target 2 (Final) */}
                      <div style={{background: 'rgba(34, 197, 94, 0.3)', padding: '1rem', borderRadius: '0.5rem', borderLeft: '4px solid #16a34a', textAlign: 'center'}}>
                        <div style={{fontSize: '0.75rem', color: '#4ade80', marginBottom: '0.25rem'}}>Target 2 (Final)</div>
                        <div style={{fontSize: '1.25rem', fontWeight: 700, color: '#22c55e'}}>
                          ₹{(() => {
                            const stock = topStocks[selectedSector]?.find(s => s.symbol === selectedStock);
                            const cmp = stock?.price || 0;
                            if (stockAnalysis[selectedStock].signal === 'BUY' || stockAnalysis[selectedStock].signal === 'Weak BUY' || stockAnalysis[selectedStock].signal === 'HOLD') {
                              return (cmp * 1.08).toFixed(0); // 8% above CMP
                            } else {
                              return (cmp * 0.92).toFixed(0); // 8% below CMP
                            }
                          })()}
                        </div>
                        <div style={{fontSize: '0.7rem', color: '#94a3b8'}}>
                          {(stockAnalysis[selectedStock].signal === 'BUY' || stockAnalysis[selectedStock].signal === 'Weak BUY') ? '+8% from CMP' : '-8% from CMP'}
                        </div>
                      </div>
                      
                      {/* Stop Loss */}
                      <div style={{background: 'rgba(239, 68, 68, 0.2)', padding: '1rem', borderRadius: '0.5rem', borderLeft: '4px solid #ef4444', textAlign: 'center'}}>
                        <div style={{fontSize: '0.75rem', color: '#fca5a5', marginBottom: '0.25rem'}}>🛑 Stop Loss</div>
                        <div style={{fontSize: '1.25rem', fontWeight: 700, color: '#f87171'}}>
                          ₹{(() => {
                            const stock = topStocks[selectedSector]?.find(s => s.symbol === selectedStock);
                            const cmp = stock?.price || 0;
                            if (stockAnalysis[selectedStock].signal === 'BUY' || stockAnalysis[selectedStock].signal === 'Weak BUY' || stockAnalysis[selectedStock].signal === 'HOLD') {
                              return (cmp * 0.95).toFixed(0); // 5% below CMP
                            } else {
                              return (cmp * 1.05).toFixed(0); // 5% above CMP
                            }
                          })()}
                        </div>
                        <div style={{fontSize: '0.7rem', color: '#94a3b8'}}>
                          {(stockAnalysis[selectedStock].signal === 'BUY' || stockAnalysis[selectedStock].signal === 'Weak BUY') ? '5% below CMP' : '5% above CMP'}
                        </div>
                      </div>
                    </div>
                    
                    {/* Risk Reward Ratio */}
                    <div style={{display: 'flex', gap: '1rem', padding: '0.75rem', background: 'rgba(255,255,255,0.05)', borderRadius: '0.5rem'}}>
                      <div style={{flex: 1}}>
                        <span style={{color: '#94a3b8', fontSize: '0.8rem'}}>Risk/Reward: </span>
                        <strong style={{color: '#fbbf24'}}>1:2</strong>
                      </div>
                      <div style={{flex: 1}}>
                        <span style={{color: '#94a3b8', fontSize: '0.8rem'}}>Position Size: </span>
                        <strong>Max 5% of capital</strong>
                      </div>
                      <div style={{flex: 1}}>
                        <span style={{color: '#94a3b8', fontSize: '0.8rem'}}>Time Frame: </span>
                        <strong>2-4 weeks</strong>
                      </div>
                    </div>
                  </div>
                  
                  {/* Stock Recommendation */}
                  <div style={{
                    background: stockAnalysis[selectedStock].signal === 'BUY' ? 'rgba(34, 197, 94, 0.1)' : 
                                stockAnalysis[selectedStock].signal === 'SELL' ? 'rgba(239, 68, 68, 0.1)' : 
                                stockAnalysis[selectedStock].signal === 'Weak BUY' ? 'rgba(34, 197, 94, 0.05)' :
                                stockAnalysis[selectedStock].signal === 'Weak SELL' ? 'rgba(239, 68, 68, 0.05)' :
                                'rgba(234, 179, 8, 0.1)',
                    border: `1px solid ${stockAnalysis[selectedStock].signal === 'BUY' || stockAnalysis[selectedStock].signal === 'Weak BUY' ? '#22c55e' : 
                                         stockAnalysis[selectedStock].signal === 'SELL' || stockAnalysis[selectedStock].signal === 'Weak SELL' ? '#ef4444' : '#eab308'}`,
                    borderRadius: '0.5rem',
                    padding: '1rem'
                  }}>
                    <h5 style={{fontSize: '0.9rem', marginBottom: '0.75rem', fontWeight: 600}}>
                      💡 Trading Strategy
                    </h5>
                    <p style={{fontSize: '0.875rem', lineHeight: 1.6, margin: 0}}>
                      {(() => {
                        const stock = topStocks[selectedSector]?.find(s => s.symbol === selectedStock);
                        const cmp = stock?.price || 0;
                        const target1 = (cmp * 1.05).toFixed(0);
                        const target2 = (cmp * 1.08).toFixed(0);
                        const stopLoss = (cmp * 0.95).toFixed(0);
                        const shortTarget1 = (cmp * 0.95).toFixed(0);
                        const shortTarget2 = (cmp * 0.92).toFixed(0);
                        const shortSL = (cmp * 1.05).toFixed(0);
                        
                        if (stockAnalysis[selectedStock].signal === 'BUY') {
                          return (
                            <>
                              <strong style={{color: '#22c55e'}}>STRONG BUY:</strong> {selectedStock} shows bullish momentum (RSI: {stockAnalysis[selectedStock].rsi?.toFixed(1)}, MACD: +{stockAnalysis[selectedStock].macd?.toFixed(1)}). 
                              <br/><br/>
                              <strong>Action:</strong> Buy at current price ₹{cmp?.toLocaleString()}. 
                              Book 50% at Target 1 (₹{target1}), trail remaining to Target 2 (₹{target2}). 
                              Exit all if price closes below ₹{stopLoss}.
                            </>
                          );
                        }
                        if (stockAnalysis[selectedStock].signal === 'Weak BUY') {
                          return (
                            <>
                              <strong style={{color: '#22c55e'}}>CAUTIOUS BUY:</strong> {selectedStock} shows moderate bullish bias (RSI: {stockAnalysis[selectedStock].rsi?.toFixed(1)}). 
                              <br/><br/>
                              <strong>Action:</strong> Accumulate small position at current price ₹{cmp?.toLocaleString()}. 
                              Target: ₹{target1}. Strict SL at ₹{stopLoss}. 
                              Add more only on breakout above 9 SMA with volume.
                            </>
                          );
                        }
                        if (stockAnalysis[selectedStock].signal === 'SELL') {
                          return (
                            <>
                              <strong style={{color: '#ef4444'}}>EXIT/SHORT:</strong> {selectedStock} shows bearish momentum (RSI: {stockAnalysis[selectedStock].rsi?.toFixed(1)}, MACD: {stockAnalysis[selectedStock].macd?.toFixed(1)}). 
                              <br/><br/>
                              <strong>Action:</strong> Exit existing longs immediately. Short sellers target ₹{shortTarget2} (-8%). 
                              Stop loss for shorts at ₹{shortSL} (5% above CMP).
                            </>
                          );
                        }
                        if (stockAnalysis[selectedStock].signal === 'Weak SELL') {
                          return (
                            <>
                              <strong style={{color: '#ef4444'}}>REDUCE EXPOSURE:</strong> {selectedStock} showing weakness (RSI: {stockAnalysis[selectedStock].rsi?.toFixed(1)}). 
                              <br/><br/>
                              <strong>Action:</strong> Book partial profits on rallies. Reduce position if price closes below ₹{shortTarget1}. 
                              Re-enter only above 9 SMA (₹{stockAnalysis[selectedStock].sma9?.toLocaleString()}) with volume confirmation.
                            </>
                          );
                        }
                        // HOLD
                        return (
                          <>
                            <strong style={{color: '#eab308'}}>HOLD:</strong> {selectedStock} in consolidation phase (RSI: {stockAnalysis[selectedStock].rsi?.toFixed(1)}). 
                            <br/><br/>
                            <strong>Action:</strong> Maintain existing positions. Consider adding at ₹{(cmp * 0.97).toFixed(0)} (support). 
                            Book profits at ₹{target1} (+5%). Trail stop loss at ₹{stopLoss}.
                          </>
                        );
                      })()}
                    </p>
                  </div>
                </div>
              )}
            </div>
          )}
          
          {/* Historical Chart Section */}
          <div className="historical-section">
            <div className="historical-header">
              <h3>{selectedChartIndex} - Historical Data with 20 SMA</h3>
              <p>Price movement and 20-day Simple Moving Average</p>
            </div>
            <div style={{display: 'flex', gap: '1rem', marginBottom: '1rem'}}>
              <select 
                value={selectedChartIndex}
                onChange={(e) => setSelectedChartIndex(e.target.value)}
                className="index-select-dropdown"
                data-testid="chart-index-select"
              >
                {sortedIndices.map((idx, i) => (
                  <option key={i} value={idx.symbol}>{idx.name}</option>
                ))}
              </select>
              <select 
                value={chartTimeframe}
                onChange={(e) => setChartTimeframe(e.target.value)}
                className="timeframe-select"
                data-testid="timeframe-select"
              >
                <option value="3M">3 Months</option>
                <option value="6M">6 Months</option>
                <option value="12M">12 Months</option>
              </select>
            </div>
            
            {/* Chart Legend */}
            <div style={{display: 'flex', gap: '1.5rem', marginBottom: '1rem'}}>
              <span style={{display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.875rem', color: 'var(--text-secondary)'}}>
                <span style={{width: '20px', height: '3px', background: 'var(--accent-blue)', borderRadius: '2px'}}></span> 20 SMA
              </span>
              <span style={{display: 'flex', alignItems: 'center', gap: '0.5rem', fontSize: '0.875rem', color: 'var(--text-secondary)'}}>
                <span style={{width: '20px', height: '3px', background: 'var(--accent-green)', borderRadius: '2px'}}></span> Close Price
              </span>
            </div>
            
            {/* Simple Chart Visualization */}
            <div style={{position: 'relative', height: '300px', background: 'var(--bg-primary)', borderRadius: '0.5rem', overflow: 'hidden', marginBottom: '1rem'}}>
              <div style={{position: 'absolute', left: 0, top: '1rem', bottom: '2rem', width: '60px', display: 'flex', flexDirection: 'column', justifyContent: 'space-between', fontSize: '0.7rem', color: 'var(--text-muted)', textAlign: 'right', paddingRight: '0.5rem'}}>
                <span>{(sortedIndices.find(i => i.symbol === selectedChartIndex)?.lastPrice * 1.05)?.toFixed(0)}</span>
                <span>{sortedIndices.find(i => i.symbol === selectedChartIndex)?.lastPrice?.toFixed(0)}</span>
                <span>{(sortedIndices.find(i => i.symbol === selectedChartIndex)?.lastPrice * 0.95)?.toFixed(0)}</span>
              </div>
              <div style={{position: 'absolute', left: '65px', right: '1rem', top: '1rem', bottom: '2rem'}}>
                <div style={{position: 'absolute', height: '2px', width: '90%', left: '5%', top: '45%', background: 'var(--accent-blue)', borderRadius: '1px', transform: 'rotate(-2deg)'}}></div>
                <div style={{position: 'absolute', height: '2px', width: '90%', left: '5%', top: '40%', background: 'var(--accent-green)', borderRadius: '1px', transform: 'rotate(1deg)'}}></div>
              </div>
              <div style={{position: 'absolute', bottom: '0.5rem', left: '65px', right: '1rem', display: 'flex', justifyContent: 'space-between', fontSize: '0.7rem', color: 'var(--text-muted)'}}>
                {getChartLabels().map((month, i) => (
                  <span key={i}>{month}</span>
                ))}
              </div>
            </div>
            
            <div style={{display: 'flex', justifyContent: 'space-between', padding: '0.75rem', background: 'var(--bg-primary)', borderRadius: '0.375rem', fontSize: '0.875rem', color: 'var(--text-secondary)'}}>
              <span>Timeframe: {chartTimeframe === '3M' ? '3 Months' : chartTimeframe === '6M' ? '6 Months' : '12 Months'}</span>
              <span>Index: {selectedChartIndex}</span>
            </div>
          </div>
        </>
      )}
    </div>
  );
};

export default OverviewTab;
